 73→// sessionStatus holds workspace state gathered for banner/prompt output.
 74→type sessionStatus struct {
 75→	configLoaded   bool
 76→	setupCompleted bool
 77→	connectors     map[string]project.ConnectorState
 78→	emailTotal     int
 79→	skillCount     int
 80→	skillNames     []string
 81→}
