 83→func gatherStatus() *sessionStatus {
 84→	s := &sessionStatus{}
 85→
 86→	// Load config (graceful — may not exist)
 87→	cfg, err := project.Load()
 88→	if err == nil {
 89→		s.configLoaded = true
 90→		s.setupCompleted = cfg.SetupCompleted
 91→		s.connectors = cfg.Connectors
 92→	}
 93→
 94→	// Load DB stats (graceful — may not exist)
 95→	if !db.Exists() {
 96→		return s
 97→	}
 98→	d, err := db.Open()
 99→	if err != nil {
100→		return s
101→	}
102→	defer d.Close()
103→
104→	stats, err := email.Stats(d)
105→	if err == nil {
106→		s.emailTotal = stats.Total
107→	}
108→
109→	skills, err := session.ListSkills(d)
110→	if err == nil {
111→		s.skillCount = len(skills)
112→		for _, sk := range skills {
113→			s.skillNames = append(s.skillNames, sk.SkillName)
114→		}
115→	}
116→
117→	return s
118→}
