120→// hookOutput is the JSON structure Claude Code expects from hook stdout.
121→type hookOutput struct {
122→	SystemMessage    string            `json:"systemMessage,omitempty"`
123→	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
124→}
