167→// runUserPrompt captures a user prompt submission event.
168→func runUserPrompt() error {
169→	input, err := session.ReadStdin()
170→	if err != nil || input == nil || input.SessionID == "" {
171→		return nil // graceful no-op
172→	}
173→
174→	if !db.Exists() {
175→		return nil
176→	}
177→	d, err := db.Open()
178→	if err != nil {
179→		return nil
180→	}
181→	defer d.Close()
182→
183→	db.EnsureSessionTables(d)
184→	session.AddEvent(d, input.SessionID, "prompt", input)
185→
186→	// Log without prompt content — keep logs lightweight
187→	session.Logger().Info("prompt", "session_id", input.SessionID)
188→	session.FlushLog()
189→	return nil
190→}
