192→// runStop captures a stop event and creates a checkpoint.
193→func runStop() error {
194→	input, err := session.ReadStdin()
195→	if err != nil || input == nil || input.SessionID == "" {
196→		return nil
197→	}
198→
199→	if !db.Exists() {
200→		return nil
201→	}
202→	d, err := db.Open()
203→	if err != nil {
204→		return nil
205→	}
206→	defer d.Close()
207→
208→	db.EnsureSessionTables(d)
209→	session.AddEvent(d, input.SessionID, "stop", input)
210→	if len(input.ModifiedFiles) > 0 {
211→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
212→	}
213→
214→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
215→	session.FlushLog()
216→	return nil
217→}
