244→func buildBanner(s *sessionStatus) string {
245→	var b strings.Builder
246→
247→	b.WriteString("\n\nPowered by Nurge:\n")
248→
249→	if !s.configLoaded {
250→		b.WriteString("  Run: nurge to get started")
251→		return b.String()
252→	}
253→
254→	// Connectors
255→	hasConnectors := false
256→	for id, c := range s.connectors {
257→		if !c.Connected {
258→			continue
259→		}
260→		hasConnectors = true
261→		switch c.Type {
262→		case "email":
263→			fmt.Fprintf(&b, "  %s: %s (%s emails synced)\n", capitalize(id), c.Account, formatCount(s.emailTotal))
264→		case "crm":
265→			fmt.Fprintf(&b, "  %s: connected\n", capitalize(id))
266→		}
267→	}
268→
269→	if !hasConnectors {
270→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
271→		return b.String()
272→	}
273→
274→	// Skills
275→	fmt.Fprintf(&b, "  Skills: %d active\n", s.skillCount)
276→
277→	if s.setupCompleted {
278→		b.WriteString("  Try:\n")
279→		b.WriteString("    \"Write a cold email to the CTO at Datastack\"\n")
280→		b.WriteString("    \"Research Acme Corp and qualify them\"\n")
281→		b.WriteString("    \"Show my pipeline\"")
282→	} else {
283→		b.WriteString("  Run /nurge:setup to get started")
284→	}
285→
286→	return b.String()
287→}
