289→func buildPromptContext(s *sessionStatus) string {
290→	var b strings.Builder
291→
292→	if !s.configLoaded || !s.setupCompleted {
293→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
294→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
295→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
296→		return b.String()
297→	}
298→
299→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
300→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
301→	b.WriteString("Rules:\n")
302→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
303→	b.WriteString("- For ICP and product context, run: nurge config show --format json\n")
304→	b.WriteString("- For email patterns and insights, run: nurge context generate --format json\n")
305→	b.WriteString("- For email stats, run: nurge emails stats --format json\n")
306→	b.WriteString("- When writing outbound emails, always run: nurge send")
307→
308→	if len(s.skillNames) > 0 {
309→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
310→	}
311→
312→	return b.String()
313→}
