 62→		return false, err
 63→	}
 64→
 65→	var settings map[string]any
 66→	if err := json.Unmarshal(data, &settings); err != nil {
 67→		return false, nil
 68→	}
 69→
 70→	hooks, ok := settings["hooks"].(map[string]any)
 71→	if !ok {
 72→		return false, nil
 73→	}
 74→
 75→	for _, g := range requiredHookGroups {
 76→		for _, h := range g.hooks {
 77→			if !hookCommandExists(hooks, g.event, h.command) {
 78→				return false, nil
 79→			}
 80→		}
 81→	}
 82→	return true, nil
 83→}
 84→
 85→func (s *hooksStep) Run() error {
 86→	settingsPath := claudeSettingsPath()
 87→
 88→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 89→		return fmt.Errorf("creating .claude/: %w", err)
 90→	}
 91→
 92→	// Load existing settings or start fresh
 93→	settings := make(map[string]any)
 94→	if data, err := os.ReadFile(settingsPath); err == nil {
 95→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
 96→	}
 97→
 98→	hooks, _ := settings["hooks"].(map[string]any)
 99→	if hooks == nil {
100→		hooks = make(map[string]any)
101→	}
102→
103→	for _, g := range requiredHookGroups {
104→		// Collect commands that are missing
105→		var missing []hookEntry
106→		for _, h := range g.hooks {
107→			if !hookCommandExists(hooks, g.event, h.command) {
108→				missing = append(missing, h)
109→			}
110→		}
111→		if len(missing) == 0 {
112→			continue
113→		}
114→
115→		// Find existing matcher entry for this event+matcher, or create one
116→		eventHooks, _ := hooks[g.event].([]any)
117→		matcherIdx := -1
118→		for i, item := range eventHooks {
119→			m, ok := item.(map[string]any)
120→			if !ok {
121→				continue
122→			}
123→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
124→				matcherIdx = i
125→				break
126→			}
127→		}
128→
129→		if matcherIdx >= 0 {
130→			// Append to existing matcher entry
131→			entry := eventHooks[matcherIdx].(map[string]any)
132→			innerHooks, _ := entry["hooks"].([]any)
133→			for _, h := range missing {
134→				innerHooks = append(innerHooks, map[string]any{
135→					"type":    "command",
136→					"command": h.command,
137→				})
138→			}
139→			entry["hooks"] = innerHooks
140→		} else {
141→			// Create new matcher entry with all hooks
142→			var innerHooks []any
143→			for _, h := range g.hooks {
144→				innerHooks = append(innerHooks, map[string]any{
145→					"type":    "command",
146→					"command": h.command,
147→				})
148→			}
149→			entry := map[string]any{
150→				"matcher": g.matcher,
151→				"hooks":   innerHooks,
152→			}
153→			eventHooks = append(eventHooks, entry)
154→		}
155→		hooks[g.event] = eventHooks
156→	}
157→
158→	settings["hooks"] = hooks
159→
160→	// Set permissions so nurge commands and skill edits don't prompt
161→	permissions, _ := settings["permissions"].(map[string]any)
162→	if permissions == nil {
163→		permissions = make(map[string]any)
164→	}
165→	allow, _ := permissions["allow"].([]any)
166→	requiredPerms := []string{
167→		"Bash(nurge *)",
168→		"Read",
169→		"Edit(.claude/skills/**)",
170→	}
171→	for _, perm := range requiredPerms {
172→		if !containsString(allow, perm) {
173→			allow = append(allow, perm)
174→		}
175→	}
176→	permissions["allow"] = allow
177→	settings["permissions"] = permissions
178→
179→	data, err := json.MarshalIndent(settings, "", "  ")
180→	if err != nil {
181→		return fmt.Errorf("marshaling settings: %w", err)
182→	}
183→
184→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
185→		return fmt.Errorf("writing settings: %w", err)
186→	}
187→
188→	return nil
189→}
190→
191→// hookCommandExists checks if a specific command already exists under the given event key.
192→func hookCommandExists(hooks map[string]any, event, command string) bool {
193→	arr, ok := hooks[event].([]any)
194→	if !ok {
195→		return false
196→	}
197→	for _, item := range arr {
198→		m, ok := item.(map[string]any)
199→		if !ok {
200→			continue
201→		}
202→		innerHooks, ok := m["hooks"].([]any)
203→		if !ok {
204→			continue
205→		}
206→		for _, h := range innerHooks {
207→			hm, ok := h.(map[string]any)
208→			if !ok {
209→				continue
210→			}
211→			if cmd, ok := hm["command"].(string); ok && cmd == command {
212→				return true
213→			}
214→		}
215→	}
216→	return false
217→}
218→
219→func containsString(arr []any, s string) bool {
220→	for _, v := range arr {
221→		if str, ok := v.(string); ok && str == s {
222→			return true
223→		}
224→	}
225→	return false
226→}
227→
228→func claudeSettingsPath() string {
229→	return filepath.Join(".claude", "settings.json")
230→}
